# The schema is compiled to JSON. Search for 'deprecat' in the schema.json
uv run python -c "
from bidsschematools import schema
s = schema.load_schema()
import json

# Recursive search for 'deprecat' in the schema
def find_deprecations(obj, path=''):
    results = []
    if isinstance(obj, dict):
        for k, v in obj.items():
            if 'deprecat' in str(k).lower():
                results.append((f'{path}.{k}', type(v).__name__))
            results.extend(find_deprecations(v, f'{path}.{k}'))
    elif isinstance(obj, (list, tuple)):
        for i, v in enumerate(obj):
            results.extend(find_deprecations(v, f'{path}[{i}]'))
    elif isinstance(obj, str) and 'deprecat' in obj.lower():
        results.append((path, obj[:200]))
    return results

results = find_deprecations(dict(s))
for path, val in results[:80]:
    print(f'{path}: {val}')
" 2>&1

