from bidsschematools import schema
s = schema.load_schema()
import re

def find_deprecated(obj, path=''):
    results = []
    if isinstance(obj, str):
        if obj == 'deprecated':
            results.append(path)
    elif hasattr(obj, 'items'):
        for k, v in obj.items():
            results.extend(find_deprecated(v, f'{path}/{k}'))
    elif isinstance(obj, (list, tuple)):
        for i, v in enumerate(obj):
            results.extend(find_deprecated(v, f'{path}[{i}]'))
    else:
        s_str = str(obj)
        # Check Namespace objects
        pairs = re.findall(r\"'([^']+)':\\s*'deprecated'\", s_str)
        for field_name in pairs:
            results.append(f'{path}/{field_name}')
    return results

