import re

# Search more broadly for BasedOn in sidecar rules
def find_field(obj, target, path=''):
    results = []
    if isinstance(obj, str) and target.lower() in obj.lower():
        results.append((path, obj))
    elif hasattr(obj, 'items'):
        for k, v in obj.items():
            if target.lower() in str(k).lower():
                results.append((f'{path}/{k}', str(v)[:200]))
